// Join: PAI accounts + PAI renewals + Slack channels + Slack users
const config = $('Configuration').first().json;
const channelPrefix = config.channelPrefix;
const companyDomain = config.companyDomain;
const minACV = config.minRenewalACV;
const useTestChannel = config.useTestChannel;
const testChannelId = config.testChannelId;
const testAccountName = config.testAccountName || '';

// --- CSV Parser ---
function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

function parseCsv(csvText) {
  if (!csvText || typeof csvText !== 'string') return [];
  const lines = csvText.split('\n').filter(l => l.trim());
  if (lines.length < 2) return [];
  const headers = parseCsvLine(lines[0]);
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const vals = parseCsvLine(lines[i]);
    const obj = {};
    headers.forEach((h, idx) => { obj[h] = vals[idx] || ''; });
    rows.push(obj);
  }
  return rows;
}

// --- Parse PAI accounts ---
const accountsCsv = $('Query Customer Accounts').first().json.data || '';
const accounts = parseCsv(accountsCsv);
console.log(`Parsed ${accounts.length} customer accounts`);
if (accounts.length > 0) console.log('Account headers:', Object.keys(accounts[0]));

// --- Parse PAI renewals ---
const renewalsCsv = $('Query Open Renewals').first().json.data || '';
const allRenewals = parseCsv(renewalsCsv);
const renewals = allRenewals.filter(r => (r['Opportunity Type'] || '').toLowerCase().includes('renewal'));
console.log(`Parsed ${allRenewals.length} open opps, ${renewals.length} are Renewal type`);

// --- Build Slack channel lookup by name ---
const slackChannelsRaw = $('Get Slack Channels').first().json;
let slackChannels = [];
if (slackChannelsRaw && slackChannelsRaw.ok && Array.isArray(slackChannelsRaw.channels)) {
  slackChannels = slackChannelsRaw.channels;
}
const channelByName = {};
for (const ch of slackChannels) {
  if (ch.name) {
    channelByName[ch.name.toLowerCase()] = { id: ch.id, name: ch.name };
  }
}
console.log(`Indexed ${Object.keys(channelByName).length} Slack channels`);

// --- Build Slack user mapping ---
const slackUsersRaw = $('Get Slack Users').first().json;
let slackMembers = [];
if (slackUsersRaw && slackUsersRaw.ok && Array.isArray(slackUsersRaw.members)) {
  slackMembers = slackUsersRaw.members;
}
const userMapping = {};
for (const user of slackMembers) {
  if (user.deleted || user.is_bot || user.id === 'USLACKBOT') continue;
  const email = user.profile?.email || '';
  if (email && email.endsWith('@' + companyDomain)) {
    const realName = user.profile?.real_name || user.real_name || '';
    if (realName) userMapping[realName] = user.id;
  }
}
console.log(`User mapping: ${Object.keys(userMapping).length} internal users`);

// --- Build renewal lookup ---
const renewalByAccount = {};
for (const r of renewals) {
  const acctName = r['Account Name'] || '';
  const acv = parseFloat(r['Amount (Converted)'] || r['Amount'] || '0');
  const closeDate = r['Close Date'] || '';
  const stage = r['Stage'] || '';
  if (!renewalByAccount[acctName] || acv > (renewalByAccount[acctName].acv || 0)) {
    renewalByAccount[acctName] = { acv, closeDate, stage };
  }
}

// --- Join: filter by ACV, resolve channels ---
const results = [];
const skipped = [];
for (const acct of accounts) {
  const accountName = acct['Account Name'] || '';
  if (!accountName) continue;

  const renewal = renewalByAccount[accountName];
  const renewalACV = renewal?.acv || 0;
  if (renewalACV < minACV) continue;

  // Channel resolution: 
  // 1. Try Slack_Channel__c field from PAI (mapped from Salesforce)
  // 2. Fall back to naming convention: customer-{normalized-name}
  let channelId = '';
  let channelName = '';
  let matchMethod = '';

  const sfChannelName = (acct['Slack Channel'] || acct['Slack_Channel__c'] || acct['slack_channel__c'] || '').trim().replace(/^#/, '');

  if (sfChannelName) {
    const ch = channelByName[sfChannelName.toLowerCase()];
    if (ch) {
      channelId = ch.id;
      channelName = '#' + ch.name;
      matchMethod = 'SF field';
    } else {
      console.log(`  ⚠️ ${accountName}: SF field="${sfChannelName}" but channel not found in Slack`);
    }
  }

  if (!channelId) {
    // Fallback: naming convention
    const normalized = accountName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
    const conventionName = channelPrefix + normalized;
    const ch = channelByName[conventionName];
    if (ch) {
      channelId = ch.id;
      channelName = '#' + ch.name;
      matchMethod = 'convention';
    }
  }

  if (!channelId && !useTestChannel) {
    skipped.push(`${accountName} ($${renewalACV.toLocaleString()} ACV) - no channel found`);
    continue;
  }

  const ownerName = acct['Account Owner (name)'] || '';
  const health = acct['Predicted Account Health'] || '';
  const domain = acct['Domain'] || '';
  const industry = acct['Industry'] || '';

  let renewalDate = 'TBD';
  if (renewal?.closeDate) {
    const d = new Date(renewal.closeDate);
    if (!isNaN(d)) renewalDate = `${(d.getMonth()+1).toString().padStart(2,'0')}/${d.getFullYear()}`;
  }

  results.push({
    accountName,
    accountOwner: ownerName,
    health,
    renewalACV,
    renewalCloseDate: renewalDate,
    renewalStage: renewal?.stage || '',
    industry,
    domain,
    slackChannelId: useTestChannel ? testChannelId : channelId,
    slackChannelName: channelName || '(test)',
    userMapping,
    isPublicCompany: !!(domain && industry),
    matchMethod
  });
}

console.log(`\n=== RESULTS: ${results.length} accounts qualified ===`);
results.forEach(r => console.log(`  ✅ ${r.accountName}: $${r.renewalACV.toLocaleString()} → ${r.slackChannelName} [${r.matchMethod}]`));

if (skipped.length > 0) {
  console.log(`\n=== SKIPPED: ${skipped.length} accounts ===`);
  skipped.forEach(s => console.log(`  ⚠️ ${s}`));
}

if (results.length === 0) {
  return [{ json: { error: 'No accounts qualified', accountCount: accounts.length, renewalCount: renewals.length } }];
}

// Test account filter
if (useTestChannel && testAccountName) {
  const filtered = results.filter(r => r.accountName.toLowerCase().includes(testAccountName.toLowerCase()));
  if (filtered.length > 0) {
    console.log(`TEST MODE: Filtered to ${filtered.length} account(s) matching "${testAccountName}"`);
    return filtered.map(r => ({ json: r }));
  }
}

return results.map(r => ({ json: r }));

const item = $input.first().json;
const account = $('Build Customer Update Prompt v3').first().json;

let message = item.output || item.text || item.response || item.message || '';

if (!message) {
  const stringFields = Object.entries(item).filter(([key, val]) => typeof val === 'string' && val.length > 100);
  if (stringFields.length > 0) {
    message = stringFields[0][1];
  }
}

// Extract PAI_ID from first line if present
let paiId = '';
const paiMatch = message.match(/^PAI_ID:(\d+)\s*/);
if (paiMatch) {
  paiId = paiMatch[1];
  message = message.replace(/^PAI_ID:\d+\s*\n?/, '').trim();
  console.log(`[${account.accountName}] Backstory ID: ${paiId}`);
}

// Split on DETAIL_BREAK marker
let aboveFold = message;
let belowFold = '';

if (message.includes('---DETAIL_BREAK---')) {
  const parts = message.split('---DETAIL_BREAK---');
  aboveFold = parts[0].trim();
  belowFold = parts[1].trim();
}

console.log(`[${account.accountName}] Above fold: ${aboveFold.length} chars, Below fold: ${belowFold.length} chars`);

return {
  json: {
    accountName: account.accountName,
    slackChannelId: account.slackChannelId,
    userMapping: account.userMapping,
    paiId: paiId,
    aboveFold: aboveFold,
    belowFold: belowFold,
    message: aboveFold + '\n\n' + belowFold,
    messageBody: aboveFold + '\n\n' + belowFold
  }
};

// Post-process: replace full names with Slack @mentions
const item = $input.first();
const userMapping = item.json.userMapping || {};

function replaceNames(text) {
  if (!text) return text;
  let result = text;
  Object.entries(userMapping).forEach(([fullName, slackId]) => {
    const namePattern = new RegExp(
      `\\b${fullName.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\$&')}\\s*(?:\\(external\\))?\\b`,
      'gi'
    );
    result = result.replace(namePattern, `<@${slackId}>`);
  });
  return result;
}

const aboveFold = replaceNames(item.json.aboveFold || '');
const belowFold = replaceNames(item.json.belowFold || '');
const message = aboveFold + (belowFold ? '\n\n' + belowFold : '');

return {
  json: {
    ...item.json,
    aboveFold,
    belowFold,
    message,
    messageBody: message
  }
};

// Check if the message indicates no material activity
const message = $json.messageBody;
const accountName = $json.accountName;

console.log(`Checking activity for ${accountName}...`);

const noActivityIndicators = [
  'no significant activity in the past 7 days',
  'no activity in the past 7 days',
  'no new risks identified this week',
  'no recent activity',
  'no updates this week'
];

let noActivityCount = 0;
noActivityIndicators.forEach(indicator => {
  if (message.toLowerCase().includes(indicator)) {
    noActivityCount++;
  }
});

const hasNoActivityInDevelopments = message.toLowerCase().includes('no significant activity in the past 7 days');
const hasNoRisks = message.toLowerCase().includes('no new risks identified this week');
const messageLength = message.length;

if (noActivityCount >= 2 || (hasNoActivityInDevelopments && hasNoRisks)) {
  console.log(`SKIPPING ${accountName} - No material activity detected`);
  return [];
}

if (messageLength < 200) {
  console.log(`SKIPPING ${accountName} - Message too short (${messageLength} chars)`);
  return [];
}

console.log(`POSTING ${accountName} - Material activity detected (${messageLength} chars)`);
return [{ json: $json }];

const item = $json;

// Single section block with all content - let Slack naturally truncate
const fullText = item.belowFold 
  ? item.aboveFold + '\n\n' + item.belowFold
  : item.aboveFold;

// Section block max is 3000 chars - trim if needed
const blockText = fullText.substring(0, 3000);

const payload = {
  channel: item.slackChannelId,
  text: item.aboveFold,  // fallback for notifications
  blocks: [
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: blockText
      }
    }
  ],
  unfurl_links: false,
  unfurl_media: false
};

return {
  json: {
    slackPayload: JSON.stringify(payload)
  }
};

// Collect all accounts that were posted
const postResults = $('Post to Slack').all();
const buildResults = $('Build Account List').all();
const filterResults = $('Filter: Skip if no activity').all();

const totalQualified = buildResults.length;
const totalPosted = postResults.length;
const totalSkipped = totalQualified - filterResults.length;

// Build summary of posted accounts
const posted = [];
const failed = [];

for (const item of postResults) {
  const slackResp = item.json;
  const ok = slackResp.ok;
  const channel = slackResp.channel || 'unknown';

  // Try to get account name from earlier in the chain
  posted.push({
    channel: channel,
    ok: ok,
    error: slackResp.error || null
  });

  if (!ok) {
    failed.push({ channel, error: slackResp.error });
  }
}

// Build the accounts list from Build Account List for full context
const accountList = [];
for (const item of buildResults) {
  accountList.push({
    name: item.json.accountName,
    acv: item.json.renewalACV,
    channel: item.json.slackChannelName,
    channelId: item.json.slackChannelId
  });
}

// Sort by ACV descending
accountList.sort((a, b) => b.acv - a.acv);

// Build summary message
const now = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric', year: 'numeric' });
let msg = `*Weekly Channel Updates — Run Summary*\n${now}\n\n`;
msg += `*Accounts qualified:* ${totalQualified}\n`;
msg += `*Posted:* ${totalPosted}\n`;
msg += `*Skipped (no activity):* ${totalSkipped}\n`;
if (failed.length > 0) {
  msg += `*Failed:* ${failed.length}\n`;
}
msg += `\n*Posted to:*\n`;

for (const acct of accountList) {
  const acvStr = '$' + acct.acv.toLocaleString();
  // Check if this account was in the posted results
  const wasPosted = posted.some(p => p.channel === acct.channelId && p.ok);
  const wasFailed = failed.some(f => f.channel === acct.channelId);
  let status = '⏭️';  // skipped
  if (wasPosted) status = '✅';
  if (wasFailed) status = '❌';
  msg += `${status} ${acct.name} — ${acvStr} — ${acct.channel}\n`;
}

if (failed.length > 0) {
  msg += `\n*Failures:*\n`;
  for (const f of failed) {
    msg += `❌ ${f.channel}: ${f.error}\n`;
  }
}

msg += `\n_Backstory MCP v3 — workflow GEVPltWL6r4SIIaW_`;

return {
  json: {
    summaryMessage: msg,
    totalQualified,
    totalPosted,
    totalSkipped,
    failedCount: failed.length
  }
};
